// BAD — ConcurrentModificationException
for (String s : list) {
    if (s.startsWith("x")) {
        list.remove(s);  // throws!
    }
}

// GOOD — Iterator.remove()
Iterator<String> it = list.iterator();
while (it.hasNext()) {
    if (it.next().startsWith("x")) {
        it.remove();  // safe
    }
}

