    .filter(s -> !s.startsWith("x"))
    .toList();

// Comparable — natural ordering (class implements it)
public class Employee implements Comparable<Employee> {
    private String name;
    private int age;

    @Override
    public int compareTo(Employee other) {
        return Integer.compare(this.age, other.age); // natural order: by age
    }
}
Collections.sort(employees); // uses compareTo()

// Comparator — external, pluggable ordering
Comparator<Employee> byName = Comparator.comparing(Employee::getName);
Comparator<Employee> bySalaryDesc = Comparator.comparingDouble(Employee::getSalary).reversed();
Comparator<Employee> byDeptThenName = Comparator.comparing(Employee::getDept)
    .thenComparing(Employee::getName); // chain comparators

// Null-safe comparators
Comparator<Employee> nullSafe = Comparator.comparing(
    Employee::getName, Comparator.nullsLast(Comparator.naturalOrder()));

employees.sort(byName);        // sort by name
employees.sort(bySalaryDesc);  // sort by salary descending

