// What happens when you call map.put(key, value):

// Step 1: Compute hash
int hash = key.hashCode();
hash = hash ^ (hash >>> 16);  // spread high bits

// Step 2: Find bucket
int index = (table.length - 1) & hash;  // fast modulo

// Step 3: Insert or handle collision
// If table[index] is null → create new Node
// If table[index] exists:
//   - Compare hash AND key.equals() for each node
//   - If match found → replace value
//   - If no match → append to list/tree

// Step 4: Check load factor
// If size > capacity * 0.75 → resize (double capacity, rehash all)

// Simple LRU Cache using LinkedHashMap
public class LRUCache<K, V> extends LinkedHashMap<K, V> {
    private final int maxSize;

    public LRUCache(int maxSize) {
        super(maxSize, 0.75f, true); // true = access-order
        this.maxSize = maxSize;
    }

    @Override
    protected boolean removeEldestEntry(Map.Entry<K, V> eldest) {
        return size() > maxSize; // auto-evict when over capacity
    }
}

LRUCache<String, String> cache = new LRUCache<>(3);
cache.put("a", "1"); cache.put("b", "2"); cache.put("c", "3");
cache.get("a");      // access "a" — moves to end
cache.put("d", "4"); // evicts "b" (least recently accessed)

// TreeMap — sorted by keys (Red-Black Tree, O(log n))
TreeMap<String, Integer> sorted = new TreeMap<>();
sorted.put("banana", 2); sorted.put("apple", 1); sorted.put("cherry", 3);
sorted.firstKey();        // "apple" (smallest)
sorted.lastKey();         // "cherry" (largest)
sorted.floorKey("cat");   // "cherry" won't work, "banana" (<=)
sorted.ceilingKey("b");   // "banana" (>=)
sorted.subMap("apple", "cherry"); // {apple=1, banana=2}

// computeIfAbsent — create value if key is missing
Map<String, List<String>> groupedByDept = new HashMap<>();
for (Employee e : employees) {
    // OLD way: if (!map.containsKey(dept)) map.put(dept, new ArrayList<>());
    groupedByDept.computeIfAbsent(e.getDept(), k -> new ArrayList<>())
                 .add(e.getName()); // creates list only on first access
}

