// PECS: Producer Extends, Consumer Super

// Producer — read from it (extends)
void printAll(List<? extends Number> list) {
    for (Number n : list) {
        System.out.println(n); // Safe to read as Number
    }
    // list.add(1); // COMPILE ERROR — can't write!
}
printAll(List.of(1, 2, 3));       // List<Integer> ✅
printAll(List.of(1.0, 2.0));       // List<Double> ✅

// Consumer — write to it (super)
void addNumbers(List<? super Integer> list) {
    list.add(1);       // Safe to write Integer
    list.add(2);
    // Integer n = list.get(0); // COMPILE ERROR — returns Object
}
addNumbers(new ArrayList<Number>());  // ✅
addNumbers(new ArrayList<Object>());  // ✅

